from moto import mock_rds
import boto3

@mock_rds
def test_describe_db_clusters_with_arn():
    client = boto3.client("rds", region_name="us-east-1")
    client.create_db_cluster(
        DBClusterIdentifier="test-cluster-1",
        Engine="aurora-mysql",
        MasterUsername="root",
        MasterUserPassword="test123456789"
    )
    try:
        # This should succeed
        client.describe_db_clusters(DBClusterIdentifier="arn:aws:rds:us-east-1:123456789012:cluster:test-cluster-1")
        print("Test passed: Cluster found using ARN.")
    except Exception as e:
        print(f"Test failed: {e}")

if __name__ == "__main__":
    test_describe_db_clusters_with_arn()
